```plantuml
@startuml
class Leistungspaket {
  - bezeichnung: String
  - preis: BigDecimal
}

class LeistungspaketBuchung {
  - leistungspaket: Leistungspaket
  - buchung: Buchung
  - anzahl: int
}

class LeistungspaketBetreuer {
  - leistungspaket: Leistungspaket
  - betreuer: Betreuer
}

class Luxuspaketpaket {
  - bezeichnung: String
  - leistungspaket: Leistungspaket
}

class Buchung {
  - hotelZimmer: Hotelzimmer
  - gast: Gast
  - anreiseDatum: LocalDate
  - abreiseDatum: LocalDate
}

class Hotelzimmer {
  - nummer: int
  - personen: int
}

class Gast {
  - kundenNr: int
  - name: String
  - adresse: Adresse
}

class HotelzimmerKategorie {
  - hotelZimmer: Hotelzimmer
  - kategorie: Kategorie
}

class Kategorie {
  - id: int
  - bezeichnung: String
}

class HotelzimmerMitarbeiter {
  - hotelZimmer: HotelzimmerMitarbeiter
  - mitarbeiter: Mitarbeiter
  - hotelZimmer: Hotelzimmer
  - mitarbeiter: Mitarbeiter
  - datum: LocalDate
}

class Mitarbeiter {
  - svnr: String
  - name: String
  - adresse: String
}

class Betreuer {
  - mitarbeiter: Mitarbeiter
  - fach: String
}

Leistungspaket "1" -- "*" Luxuspaketpaket
Leistungspaket -- Mitarbeiter
Leistungspaket .. LeistungspaketBuchung
Leistungspaket .. LeistungspaketBetreuer

Buchung "*" -- "1" Hotelzimmer
Buchung "*" -- "1" Gast
Buchung -- LeistungspaketBuchung

Hotelzimmer -- Kategorie
Hotelzimmer .. HotelzimmerKategorie
Hotelzimmer -- Mitarbeiter
Hotelzimmer .. HotelzimmerMitarbeiter

Mitarbeiter <|-- Betreuer

note "ein Luxuspaketpaket hat mehrere Einträge mit der gleichen Bezeichnung" as N1
HotelzimmerMitarbeiter .. N1
@enduml
```
